// Seeded pseudorandom generator to guarantee consistent generation on refresh
function selectWithSeed(arr: any[], seed: number) {
  const index = Math.floor(Math.abs(Math.sin(seed) * 100000)) % arr.length;
  return arr[index];
}

// Generate extremely long texts (100 to 160 paragraphs each, like a massive story/novel/paper)
function generateBookContent(isHindi: boolean, bookSeed: number): string[] {
  const targetParagraphCount = 100 + (bookSeed % 61); // 100 to 160 paragraphs!
  const content: string[] = [];
  
  for (let p = 1; p <= targetParagraphCount; p++) {
    const pSeed = bookSeed + p * 883;
    if (isHindi) {
      // Build a paragraph of 3 beautiful narrative sentences in Hindi
      const s1 = `${selectWithSeed(hiConnectors, pSeed)} ${selectWithSeed(hiSubjects, pSeed + 1)} ${selectWithSeed(hiVerbs, pSeed + 2)} ${selectWithSeed(hiObjects, pSeed + 3)}`;
      const s2 = `${selectWithSeed(hiSubjects, pSeed + 4)} ${selectWithSeed(hiVerbs, pSeed + 5)} ${selectWithSeed(hiObjects, pSeed + 6)}`;
      const s3 = `यहीं कारण है कि ${selectWithSeed(hiSubjects, pSeed + 7)} ${selectWithSeed(hiVerbs, pSeed + 8)} ${selectWithSeed(hiObjects, pSeed + 9)}`;
      content.push(`${s1} ${s2} ${s3}`);
    } else {
      // Build a paragraph of 3 beautiful scientific/philosophical sentences in English
      const s1 = `${selectWithSeed(enTransitions, pSeed)} ${selectWithSeed(enSubjects, pSeed + 1)} ${selectWithSeed(enVerbs, pSeed + 2)} ${selectWithSeed(enObjects, pSeed + 3)}`;
      const s2 = `${selectWithSeed(enSubjects, pSeed + 4)} ${selectWithSeed(enVerbs, pSeed + 5)} ${selectWithSeed(enObjects, pSeed + 6)}`;
      const s3 = `This explains why ${selectWithSeed(enSubjects, pSeed + 7)} ${selectWithSeed(enVerbs, pSeed + 8)} ${selectWithSeed(enObjects, pSeed + 9)}`;
      content.push(`${s1} ${s2} ${s3}`);
    }
  }
  return content;
}

