// We generate exactly 200 books, alternating back and forth:
// Book 1: English
// Book 2: Hindi
// Book 3: English
// Book 4: Hindi
// ...
// This guarantees perfect alternation and matches the user's requirement.
for (let i = 1; i <= 200; i++) {
  const isHindi = (i % 2 === 0);
  const bSeed = i * 299;
  
  if (isHindi) {
    const prefix = selectWithSeed(hiTitlePrefix, bSeed);
    const middle = selectWithSeed(hiTitleMiddle, bSeed + 1);
    const suffix = selectWithSeed(hiTitleSuffix, bSeed + 2);
    const author = selectWithSeed(hiAuthors, bSeed + 3);
    const category = selectWithSeed(hiMainCategories, bSeed + 4);
    
    const title = `${prefix} ${middle} ${suffix}`;
    const authorYear = `${author}, ${(1950 + (bSeed % 71))}`;
    const filename = `Pustakalay / ${category} / ${prefix}_${middle}_Granth_${i}.epub`;
    
    generatedBooks.push({
      id: `dynamic_hindi_b${i}`,
      title,
      author: authorYear,
      filename,
      content: generateBookContent(true, bSeed)
    });
  } else {
    const f = selectWithSeed(enFields, bSeed);
    const m = selectWithSeed(enMidTerms, bSeed + 1);
    const e = selectWithSeed(enEndTerms, bSeed + 2);
    const author = selectWithSeed(enAuthors, bSeed + 3);
    
    const title = `${f.term} ${m} ${e}`;
    const authorYear = `${author}, ${(1980 + (bSeed % 47))}`;
    const filename = `Archive / ${f.cat} / ${f.term}_${f.ext}_v${(i % 4) + 1}.pdf`;
    
    generatedBooks.push({
      id: `dynamic_english_b${i}`,
      title,
      author: authorYear,
      filename,
      content: generateBookContent(false, bSeed)
    });
  }
}

